    inputCode: "<ul id=\"output-list\"><\/ul>\r\n\r\n<script>\r\n    let a = 10, b = 3;\r\n\r\n    const results = [\r\n        `a + b = ${a + b}`,       \/\/ 13\r\n        `a - b = ${a - b}`,       \/\/ 7\r\n        `a * b = ${a * b}`,       \/\/ 30\r\n        `a \/ b = ${a \/ b}`,       \/\/ 3.333...\r\n        `a % b = ${a % b}`,       \/\/ 1\r\n        `a ** b = ${a ** b}`,     \/\/ 1000\r\n        `++a = ${++a}`,           \/\/ Pre-increment, a becomes 11\r\n        `a++ = ${a++}`,           \/\/ Post-increment, returns 11 then a becomes 12\r\n        `--a = ${--a}`,           \/\/ Pre-decrement, a becomes 11\r\n        `a-- = ${a--}`,           \/\/ Post-decrement, returns 11 then a becomes 10\r\n        `Final value of a = ${a}` \/\/ Back to 10\r\n    ];\r\n\r\n    const list = document.getElementById(\"output-list\");\r\n\r\n    results.forEach(result => {\r\n        const li = document.createElement(\"li\");\r\n        li.textContent = result;\r\n        list.appendChild(li);\r\n    });\r\n<\/script>",
