    description: "",
    inputCode: "<ul id=\"output-list\"><\/ul>\r\n\r\n<script>\r\n    let a = 10, b = \"10\", c = 20;\r\n\r\n    const comparisons = [\r\n        `a == b \u2192 ${a == b}`,     \/\/ true\r\n        `a === b \u2192 ${a === b}`,   \/\/ false\r\n        `a != c \u2192 ${a != c}`,     \/\/ true\r\n        `a !== b \u2192 ${a !== b}`,   \/\/ true\r\n        `a > c \u2192 ${a > c}`,       \/\/ false\r\n        `a < c \u2192 ${a < c}`,       \/\/ true\r\n        `a >= c \u2192 ${a >= c}`,     \/\/ false\r\n        `a <= c \u2192 ${a <= c}`      \/\/ true\r\n    ];\r\n\r\n    const list = document.getElementById(\"output-list\");\r\n\r\n    comparisons.forEach(text => {\r\n        const li = document.createElement(\"li\");\r\n        li.textContent = text;\r\n        list.appendChild(li);\r\n    });\r\n<\/script>",
