    inputCode: "<ul id=\"output-list\"><\/ul>\r\n\r\n<script>\r\n    const results = [];\r\n\r\n    \/\/ for loop\r\n    for (let i = 0; i < 5; i++) {\r\n        results.push(`for loop: i = ${i}`);\r\n    }\r\n\r\n    \/\/ while loop\r\n    let i = 0;\r\n    while (i < 5) {\r\n        results.push(`while loop: i = ${i}`);\r\n        i++;\r\n    }\r\n\r\n    \/\/ do...while loop\r\n    let j = 0;\r\n    do {\r\n        results.push(`do...while loop: j = ${j}`);\r\n        j++;\r\n    } while (j < 5);\r\n\r\n    \/\/ for...of loop\r\n    const array = [1, 2, 3];\r\n    for (const element of array) {\r\n        results.push(`for...of loop: element = ${element}`);\r\n    }\r\n\r\n    \/\/ for...in loop\r\n    const object = { a: 1, b: 2 };\r\n    for (const property in object) {\r\n        results.push(`for...in loop: ${property} = ${object[property]}`);\r\n    }\r\n\r\n    \/\/ Render results to the list\r\n    const list = document.getElementById(\"output-list\");\r\n    results.forEach(text => {\r\n        const li = document.createElement(\"li\");\r\n        li.textContent = text;\r\n        list.appendChild(li);\r\n    });\r\n<\/script>",
