    inputCode: "<ul id=\"output-list\"><\/ul>\r\n\r\n<script>\r\n  \/\/ Global scope\r\n  let globalVar = \"I\'m global\";\r\n\r\n  function exampleFunction() {\r\n    \/\/ Function scope\r\n    let functionVar = \"I\'m in a function\";\r\n    \r\n    if (true) {\r\n      \/\/ Block scope (ES6+)\r\n      let blockVar = \"I\'m in a block\";\r\n      const anotherBlockVar = \"I\'m also in a block\";\r\n      \r\n      \/\/ Function-scoped variable due to `var`\r\n      var functionScopedVar = \"I\'m function-scoped despite being in a block\";\r\n      \r\n      \/\/ Display the block-scoped variables (only accessible within the block)\r\n      console.log(blockVar);         \/\/ \"I\'m in a block\"\r\n      console.log(anotherBlockVar);  \/\/ \"I\'m also in a block\"\r\n    }\r\n\r\n    \/\/ Block-scoped variables are not accessible outside the block\r\n    \/\/ console.log(blockVar);        \/\/ Uncaught ReferenceError: blockVar is not defined\r\n    \/\/ console.log(anotherBlockVar); \/\/ Uncaught ReferenceError: anotherBlockVar is not defined\r\n\r\n    \/\/ Function-scoped variable is accessible outside the block, within the function\r\n    console.log(functionScopedVar); \/\/ \"I\'m function-scoped despite being in a block\"\r\n  }\r\n\r\n  \/\/ Call the function to test\r\n  exampleFunction();\r\n\r\n  \/\/ Global variable is accessible anywhere in the script\r\n  console.log(globalVar);  \/\/ \"I\'m global\"\r\n<\/script>",
