    inputCode: "<ul id=\"output-list\"><\/ul>\r\n\r\n<script>\r\n    const output = [];\r\n    const fruits = [\"apple\", \"banana\", \"cherry\"];\r\n    output.push(`Initial array: ${JSON.stringify(fruits)}`);\r\n\r\n    output.push(`fruits.length \u2192 ${fruits.length}`);\r\n    output.push(`fruits.indexOf(\"banana\") \u2192 ${fruits.indexOf(\"banana\")}`);\r\n    output.push(`fruits.includes(\"cherry\") \u2192 ${fruits.includes(\"cherry\")}`);\r\n\r\n    fruits.push(\"date\");\r\n    output.push(`After push(\"date\") \u2192 ${JSON.stringify(fruits)}`);\r\n\r\n    fruits.pop();\r\n    output.push(`After pop() \u2192 ${JSON.stringify(fruits)}`);\r\n\r\n    fruits.unshift(\"avocado\");\r\n    output.push(`After unshift(\"avocado\") \u2192 ${JSON.stringify(fruits)}`);\r\n\r\n    fruits.shift();\r\n    output.push(`After shift() \u2192 ${JSON.stringify(fruits)}`);\r\n\r\n    fruits.splice(1, 1, \"blueberry\");\r\n    output.push(`After splice(1, 1, \"blueberry\") \u2192 ${JSON.stringify(fruits)}`);\r\n\r\n    const sliced = fruits.slice(1, 2);\r\n    output.push(`slice(1, 2) \u2192 ${JSON.stringify(sliced)}`);\r\n\r\n    const merged = fruits.concat([\"date\", \"elderberry\"]);\r\n    output.push(`concat([\"date\", \"elderberry\"]) \u2192 ${JSON.stringify(merged)}`);\r\n\r\n    const joined = fruits.join(\", \");\r\n    output.push(`join(\", \") \u2192 ${joined}`);\r\n\r\n    const list = document.getElementById(\"output-list\");\r\n    output.forEach(item => {\r\n        const li = document.createElement(\"li\");\r\n        li.textContent = item;\r\n        list.appendChild(li);\r\n    });\r\n<\/script>",
    outputCode: "<ul>\r\n  <li>Initial array: [\"apple\",\"banana\",\"cherry\"]<\/li>\r\n  <li>fruits.length \u2192 3<\/li>\r\n  <li>fruits.indexOf(\"banana\") \u2192 1<\/li>\r\n  <li>fruits.includes(\"cherry\") \u2192 true<\/li>\r\n  <li>After push(\"date\") \u2192 [\"apple\",\"banana\",\"cherry\",\"date\"]<\/li>\r\n  <li>After pop() \u2192 [\"apple\",\"banana\",\"cherry\"]<\/li>\r\n  <li>After unshift(\"avocado\") \u2192 [\"avocado\",\"apple\",\"banana\",\"cherry\"]<\/li>\r\n  <li>After shift() \u2192 [\"apple\",\"banana\",\"cherry\"]<\/li>\r\n  <li>After splice(1, 1, \"blueberry\") \u2192 [\"apple\",\"blueberry\",\"cherry\"]<\/li>\r\n  <li>slice(1, 2) \u2192 [\"blueberry\"]<\/li>\r\n  <li>concat([\"date\", \"elderberry\"]) \u2192 [\"apple\",\"blueberry\",\"cherry\",\"date\",\"elderberry\"]<\/li>\r\n  <li>join(\", \") \u2192 apple, blueberry, cherry<\/li>\r\n<\/ul>",
