    inputCode: "<ul id=\"output-list\"><\/ul>\r\n\r\n<script>\r\n    const output = [];\r\n\r\n    const items = [5, 2, 8, 1, 4];\r\n    output.push(`Original items: ${JSON.stringify(items)}`);\r\n\r\n    \/\/ sort\r\n    items.sort((a, b) => a - b);\r\n    output.push(`Sorted (ascending) \u2192 ${JSON.stringify(items)}`);\r\n\r\n    \/\/ reverse\r\n    items.reverse();\r\n    output.push(`Reversed \u2192 ${JSON.stringify(items)}`);\r\n\r\n    \/\/ flat\r\n    const nested = [1, [2, [3, 4]]];\r\n    const flattened = nested.flat(2);\r\n    output.push(`Flattened [1, [2, [3, 4]]] with flat(2) \u2192 ${JSON.stringify(flattened)}`);\r\n\r\n    \/\/ flatMap\r\n    const sentences = [\"Hello world\", \"JavaScript is fun\"];\r\n    const words = sentences.flatMap(s => s.split(\" \"));\r\n    output.push(`flatMap sentences \u2192 ${JSON.stringify(words)}`);\r\n\r\n    \/\/ Render to HTML\r\n    const list = document.getElementById(\"output-list\");\r\n    output.forEach(item => {\r\n        const li = document.createElement(\"li\");\r\n        li.textContent = item;\r\n        list.appendChild(li);\r\n    });\r\n<\/script>",
