    id: 25,
    title: "Selecting Elements",
    description: "",
    inputCode: "<div id=\"myId\">This is a div with an ID of \"myId\"<\/div>\r\n<div class=\"myClass\">This is a div with class \"myClass\"<\/div>\r\n<div class=\"myClass\">This is another div with class \"myClass\"<\/div>\r\n<p>This is a paragraph.<\/p>\r\n\r\n<script>\r\n    \/\/ By ID\r\n    const elementById = document.getElementById(\"myId\");\r\n    console.log(\"By ID:\", elementById.textContent);\r\n\r\n    \/\/ By class name\r\n    const elementsByClassName = document.getElementsByClassName(\"myClass\");\r\n    console.log(\"By Class Name:\", elementsByClassName[0].textContent, elementsByClassName[1].textContent);\r\n\r\n    \/\/ By tag name\r\n    const divsByTagName = document.getElementsByTagName(\"div\");\r\n    console.log(\"By Tag Name (divs):\", divsByTagName[0].textContent, divsByTagName[1].textContent, divsByTagName[2].textContent);\r\n\r\n    \/\/ CSS selector (single element)\r\n    const elementByQuerySelector = document.querySelector(\".myClass\");\r\n    console.log(\"By Query Selector (first .myClass):\", elementByQuerySelector.textContent);\r\n\r\n    \/\/ CSS selector (all matching elements)\r\n    const elementsByQuerySelectorAll = document.querySelectorAll(\"div.myClass\");\r\n    elementsByQuerySelectorAll.forEach(element => {\r\n        console.log(\"By Query Selector All (all .myClass):\", element.textContent);\r\n    });\r\n<\/script>",
    outputCode: "<p>By ID: This is a div with an ID of \"myId\"<\/p>\r\n<p>By Class Name: This is a div with class \"myClass\" This is another div with class \"myClass\"<\/p>\r\n<p>By Tag Name (divs): This is a div with an ID of \"myId\" This is a div with class \"myClass\" This is another div with class \"myClass\"<\/p>\r\n<p>By Query Selector (first .myClass): This is a div with class \"myClass\"<\/p>\r\n<p>By Query Selector All (all .myClass): This is a div with class \"myClass\"<\/p>\r\n<p>By Query Selector All (all .myClass): This is another div with class \"myClass\"<\/p>",
