    description: "async/await is a modern way to handle asynchronous operations in JavaScript, making code easier to read and maintain compared to callbacks or .then() chaining",
    inputCode: "<ul id=\"output-list\"><\/ul>\r\n\r\n<script>\r\n  \/\/ Simulate fetchData and processData functions\r\n  const fetchData = () => {\r\n    return new Promise((resolve) => {\r\n      setTimeout(() => {\r\n        resolve(\"Fetched data!\");\r\n      }, 1000); \/\/ Simulate a network delay of 1 second\r\n    });\r\n  };\r\n\r\n  const processData = (data) => {\r\n    return new Promise((resolve) => {\r\n      setTimeout(() => {\r\n        resolve(`${data} processed successfully!`);\r\n      }, 1500); \/\/ Simulate a processing delay of 1.5 seconds\r\n    });\r\n  };\r\n\r\n  \/\/ Async function to fetch and process data\r\n  async function getData() {\r\n    try {\r\n      const data = await fetchData();\r\n      console.log(data);\r\n\r\n      const processedData = await processData(data);\r\n      console.log(processedData);\r\n\r\n      return processedData;\r\n    } catch (error) {\r\n      console.error(error);\r\n    }\r\n  }\r\n\r\n  \/\/ Call getData and display result in HTML\r\n  getData().then((result) => {\r\n    const output = [`Final processed result: ${result}`];\r\n    const list = document.getElementById(\"output-list\");\r\n\r\n    output.forEach(item => {\r\n      const li = document.createElement(\"li\");\r\n      li.textContent = item;\r\n      list.appendChild(li);\r\n    });\r\n  });\r\n<\/script>",
    outputCode: "<ul id=\"output-list\">\r\n  <li>Final processed result: Fetched data! processed successfully!<\/li>\r\n<\/ul>",
