    title: "Fetch API",
    description: "The Fetch API is used to make HTTP requests (GET, POST, PUT, DELETE, etc.) in JavaScript. It returns a Promise, making it ideal for handling asynchronous operations.",
    inputCode: "<ul id=\"output-list\"><\/ul>\r\n\r\n<script>\r\n    const output = [];\r\n\r\n    \/\/ Basic fetch request\r\n    fetch(\'https:\/\/api.example.com\/data\')\r\n      .then(response => {\r\n        if (!response.ok) {\r\n          throw new Error(\'Network response was not ok\');\r\n        }\r\n        return response.json();\r\n      })\r\n      .then(data => {\r\n        output.push(`Basic Fetch Data: ${JSON.stringify(data)}`);\r\n      })\r\n      .catch(error => {\r\n        output.push(`Error in Basic Fetch: ${error}`);\r\n      });\r\n\r\n    \/\/ Fetch with options (POST request)\r\n    fetch(\'https:\/\/api.example.com\/data\', {\r\n      method: \'POST\',\r\n      headers: {\r\n        \'Content-Type\': \'application\/json\',\r\n        \'Authorization\': \'Bearer token\'\r\n      },\r\n      body: JSON.stringify({\r\n        name: \'John\',\r\n        age: 30\r\n      })\r\n    })\r\n      .then(response => response.json())\r\n      .then(data => {\r\n        output.push(`POST Fetch Data: ${JSON.stringify(data)}`);\r\n      })\r\n      .catch(error => {\r\n        output.push(`Error in POST Fetch: ${error}`);\r\n      });\r\n\r\n    \/\/ Using async\/await with fetch\r\n    async function fetchData() {\r\n      try {\r\n        const response = await fetch(\'https:\/\/api.example.com\/data\');\r\n        if (!response.ok) {\r\n          throw new Error(\'Network response was not ok\');\r\n        }\r\n        const data = await response.json();\r\n        output.push(`Async\/Await Fetch Data: ${JSON.stringify(data)}`);\r\n      } catch (error) {\r\n        output.push(`Error in Async\/Await Fetch: ${error}`);\r\n      }\r\n    }\r\n\r\n    fetchData();\r\n\r\n    \/\/ Display the output in the list\r\n    setTimeout(() => {\r\n      const list = document.getElementById(\"output-list\");\r\n      output.forEach(item => {\r\n        const li = document.createElement(\"li\");\r\n        li.textContent = item;\r\n        list.appendChild(li);\r\n      });\r\n    }, 1000); \/\/ Delay to ensure all async fetches complete\r\n<\/script>",
