    inputCode: "<ul id=\"output-list\"><\/ul>\r\n\r\n<script>\r\n    const output = [];\r\n\r\n    \/\/ Function that might throw an error\r\n    function riskyOperation() {\r\n        const random = Math.random();\r\n        if (random > 0.5) {\r\n            return \'Operation succeeded!\';\r\n        } else {\r\n            throw new Error(\'Something went wrong during the operation!\');\r\n        }\r\n    }\r\n\r\n    \/\/ Cleanup function that always runs\r\n    function cleanup() {\r\n        output.push(\'Cleanup completed.\');\r\n    }\r\n\r\n    try {\r\n        \/\/ Code that might throw an error\r\n        const result = riskyOperation();\r\n        output.push(`Success: ${result}`);\r\n    } catch (error) {\r\n        \/\/ Handle the error\r\n        output.push(`An error occurred: ${error.message}`);\r\n    } finally {\r\n        \/\/ Code that runs regardless of whether there was an error\r\n        cleanup();\r\n    }\r\n\r\n    \/\/ Display the output in the list\r\n    setTimeout(() => {\r\n        const list = document.getElementById(\"output-list\");\r\n        output.forEach(item => {\r\n            const li = document.createElement(\"li\");\r\n            li.textContent = item;\r\n            list.appendChild(li);\r\n        });\r\n    }, 500); \/\/ Delay to allow try...catch to complete\r\n<\/script>",
