    inputCode: "<ul id=\"output-list\"><\/ul>\r\n\r\n<script>\r\n    const output = [];\r\n\r\n    \/\/ Simulate a fetchData function that returns a Promise\r\n    function fetchData() {\r\n        return new Promise((resolve, reject) => {\r\n            const success = Math.random() > 0.5; \/\/ Simulate success or failure randomly\r\n            setTimeout(() => {\r\n                if (success) {\r\n                    resolve(\'Data fetched successfully!\');\r\n                } else {\r\n                    reject(new Error(\'Failed to fetch data\'));\r\n                }\r\n            }, 1000);\r\n        });\r\n    }\r\n\r\n    \/\/ Promise error handling\r\n    fetchData()\r\n        .then(data => {\r\n            output.push(`Promise success: ${data}`);\r\n        })\r\n        .catch(error => {\r\n            output.push(`Promise error: ${error.message}`);\r\n        });\r\n\r\n    \/\/ Async\/await error handling\r\n    async function getData() {\r\n        const defaultData = \'Fallback data\'; \/\/ Default value to return in case of error\r\n        try {\r\n            const data = await fetchData();\r\n            output.push(`Async\/Await success: ${data}`);\r\n            return data;\r\n        } catch (error) {\r\n            console.error(\'Error fetching data:\', error);\r\n            output.push(`Async\/Await error: ${error.message}`);\r\n            return defaultData;\r\n        }\r\n    }\r\n\r\n    \/\/ Call async function to handle data\r\n    getData();\r\n\r\n    \/\/ Display the output in the list\r\n    setTimeout(() => {\r\n        const list = document.getElementById(\"output-list\");\r\n        output.forEach(item => {\r\n            const li = document.createElement(\"li\");\r\n            li.textContent = item;\r\n            list.appendChild(li);\r\n        });\r\n    }, 2000); \/\/ Delay to allow async fetch to complete\r\n<\/script>",
